/**
 * REVENANT V31
 * F5 - Deterministic Nudge Engine
 *
 * STRICTLY RULE-BASED
 */

const output = [];

for (const item of $input.all()) {

    const customer = item.json;

    /*
    ------------------------------------------------------
    RULE A
    Low balance before autopay
    ------------------------------------------------------
    */

    if (
        customer.upcoming_autopay &&
        customer.current_balance < customer.upcoming_autopay.amount
    ) {

        output.push({

            json: {

                ...customer,

                nudge_intent: "LOW_BALANCE_WARNING",

                context_payload: {

                    balance: customer.current_balance,

                    bill_amount: customer.upcoming_autopay.amount,

                    due_date: customer.upcoming_autopay.due_date,

                    merchant: customer.upcoming_autopay.merchant

                }

            }

        });

        continue;
    }

    /*
    ------------------------------------------------------
    RULE B
    Loan renewal
    ------------------------------------------------------
    */

    if (
        customer.loan &&
        customer.loan.repayment_history === "GOOD"
    ) {

        output.push({

            json: {

                ...customer,

                nudge_intent: "LOAN_RENEWAL",

                context_payload: {

                    loan_id: customer.loan.loan_id,

                    maturity_date: customer.loan.maturity_date,

                    remaining_balance: customer.loan.remaining_balance

                }

            }

        });

        continue;
    }

    /*
    ------------------------------------------------------
    RULE C
    Idle balance savings opportunity
    ------------------------------------------------------
    */

    if (
        customer.current_balance >= 5000000 &&
        customer.idle_cash_days >= 30
    ) {

        output.push({

            json: {

                ...customer,

                nudge_intent: "SAVINGS_NUDGE",

                context_payload: {

                    balance: customer.current_balance,

                    idle_days: customer.idle_cash_days

                }

            }

        });

        continue;
    }

}

/*
No trigger?
No message.
No spam.
*/

return output;

// =============================================================================
// Node: Communication Consent & Frequency Cap Gate (Mock)
// Location: Between Deterministic Nudge Engine and LLM Advisory Layer
// Purpose: Enforce opt-in consent and 72‑hour frequency cap before sending nudges.
//          Uses a deterministic mock of the "user_preferences" table.
// =============================================================================

const items = $input.all();
const now = new Date();
const HOURS_72_MS = 72 * 60 * 60 * 1000;   // 72 hours in milliseconds

// -------------------------------------------------------------------
// Deterministic Mock Lookup (simulates Supabase "user_preferences")
// -------------------------------------------------------------------
// In production this would be replaced by an HTTP Request node to
// Supabase or a direct database query.  Here we derive a pseudo‑random
// but consistent result from the customer_id so that the same ID
// always gets the same mock values.
function getUserPreferences(customerId) {
  // Simple character‑code sum for deterministic variation
  let sum = 0;
  for (let i = 0; i < customerId.length; i++) {
    sum += customerId.charCodeAt(i);
  }

  // Consent: even sum → opt_in = true, odd → false
  const opt_in_marketing = (sum % 2 === 0);

  // last_nudge_timestamp: based on sum % 3
  //   % 0 → 24 hours ago (fails rate limit)
  //   % 1 → 100 hours ago (passes)
  //   % 2 → 80 hours ago (passes)
  let last_nudge_timestamp = null;
  if (sum % 3 === 0) {
    last_nudge_timestamp = new Date(now.getTime() - 24 * 60 * 60 * 1000).toISOString();
  } else if (sum % 3 === 1) {
    last_nudge_timestamp = new Date(now.getTime() - 100 * 60 * 60 * 1000).toISOString();
  } else {
    last_nudge_timestamp = new Date(now.getTime() - 80 * 60 * 60 * 1000).toISOString();
  }

  return { opt_in_marketing, last_nudge_timestamp };
}

// -------------------------------------------------------------------
// Main processing loop
// -------------------------------------------------------------------
const passedItems = [];
const droppedSummary = [];   // For internal logging only

for (const item of items) {
  const data = item.json;

  // ---------- Extract customer_id (flexible field naming) ----------
  const customerId =
    data.customer_id ||
    data.customerId ||
    (data.user && data.user.customer_id) ||
    null;

  // If we cannot determine a customer_id, drop as invalid
  if (!customerId) {
    data.nudge_gate_status = 'DROPPED_INVALID';
    droppedSummary.push({ customer: 'UNKNOWN', reason: 'DROPPED_INVALID' });
    console.warn('[Nudge Gate] Missing customer_id – item dropped');
    continue;
  }

  // ---------- Simulated user preferences lookup ----------
  const prefs = getUserPreferences(customerId);

  // ---------- Gate 1: Consent ----------
  if (!prefs.opt_in_marketing) {
    data.nudge_gate_status = 'DROPPED_CONSENT';
    droppedSummary.push({ customer: customerId, reason: 'DROPPED_CONSENT' });
    console.log(`[Nudge Gate] Consent not granted for ${customerId}`);
    continue;   // Drop item entirely
  }

  // ---------- Gate 2: Frequency Cap (72 hours) ----------
  if (prefs.last_nudge_timestamp) {
    const lastNudgeTime = new Date(prefs.last_nudge_timestamp).getTime();
    const hoursSinceLastNudge = (now.getTime() - lastNudgeTime) / (60 * 60 * 1000);

    if (hoursSinceLastNudge < 72) {
      data.nudge_gate_status = 'DROPPED_RATE_LIMIT';
      droppedSummary.push({
        customer: customerId,
        reason: 'DROPPED_RATE_LIMIT',
        lastNudge: prefs.last_nudge_timestamp,
        hoursAgo: hoursSinceLastNudge.toFixed(1)
      });
      console.log(`[Nudge Gate] Rate limit hit for ${customerId} (last nudge ${hoursSinceLastNudge.toFixed(1)}h ago)`);
      continue;
    }
  }

  // ---------- All gates passed ----------
  data.nudge_gate_status = 'PASSED';
  passedItems.push(item);
}

// -------------------------------------------------------------------
// Log dropped items summary (visible in n8n execution output)
// -------------------------------------------------------------------
if (droppedSummary.length > 0) {
  console.warn(`[Nudge Gate] Dropped ${droppedSummary.length} items:`, droppedSummary);
} else {
  console.log('[Nudge Gate] All items passed');
}

// Output only the items that passed both gates
return passedItems;

// REVENANT V31-F5 — "Outbound Dispatcher Builder" (UPDATED: interactive inline keyboards)
// Builds the Telegram Bot API JSON for outbound nudges. Context-aware
// inline keyboards turn a read-only notification into a one-tap action;
// the button's callback_data round-trips back to the main REVENANT webhook.
//
// CRITICAL: no require('crypto'), no external libraries, pure JS only.
// Telegram callback_data has a hard 64-byte limit — guarded below.

const items = $input.all();
const returnData = [];

for (const item of items) {
  const json = item.json;

  const nudge_intent = json.nudge_intent;
  const text = json.text;

  // Identity + delivery target — adjust these field names if your upstream
  // node carries them under different keys; this defends against a few
  // likely shapes without assuming one rigidly.
  const customer_id = json.customer_id || (json.canonical_ticket && json.canonical_ticket.customer_id) || null;
  const chat_id = json.chat_id || json.telegram_chat_id || (json.canonical_ticket && json.canonical_ticket.telegram_chat_id) || null;

  // Base payload — every nudge gets at least this, even with no button.
  const telegram_payload = {
    chat_id: chat_id,
    text: text,
    parse_mode: 'HTML',
  };

  let inlineButton = null;

  // ---------------------------------------------------------------------
  // Context-aware keyboard selection
  // ---------------------------------------------------------------------
  switch (nudge_intent) {
    case 'LOW_BALANCE_WARNING':
      inlineButton = {
        text: "💳 Hisobni to'ldirish (Top Up)",
        callback_data: `INTENT_TOPUP|${customer_id}`,
      };
      break;

    case 'LOAN_RENEWAL':
      inlineButton = {
        text: '🔄 Qayta moliyalashtirish (Renew)',
        callback_data: `INTENT_LOAN|${customer_id}`,
      };
      break;

    case 'SAVINGS_NUDGE':
      inlineButton = {
        text: '💰 Omonat ochish (Open Deposit)',
        callback_data: `INTENT_DEPOSIT|${customer_id}`,
      };
      break;

    default:
      // Unknown / purely informational nudge -> no button, unchanged behavior.
      inlineButton = null;
  }

  // Fail safe rather than fail silent: don't ship an unusable button.
  if (inlineButton) {
    if (!customer_id) {
      json.dispatcher_warning = `NO_CUSTOMER_ID_FOR_NUDGE: ${nudge_intent}`;
      inlineButton = null;
    } else if (inlineButton.callback_data.length > 64) {
      json.dispatcher_warning = `CALLBACK_DATA_EXCEEDS_64_BYTES: ${nudge_intent}`;
      inlineButton = null;
    }
  }

  if (inlineButton) {
    telegram_payload.reply_markup = {
      inline_keyboard: [[inlineButton]],
    };
  }

  json.telegram_payload = telegram_payload;
  returnData.push(item);
}

return returnData;
